#' Dynamic CFA Fit-Index Cutoffs
#'
#' Tests whether the observed one-factor categorical-CFA fit
#' indices (CFI, RMSEA, SRMR) are consistent with the data being
#' generated by a unidimensional Rasch / Partial Credit Model.
#' 
#' For each iteration a dataset is simulated from the fitted PCM
#' (or RM, for dichotomous data) using observed item parameters
#' and a resampled person distribution; lavaan::cfa(ordered = TRUE)
#' is fitted on the simulation and CFI / RMSEA / SRMR are recorded.
#' The result is a parametric-bootstrap null distribution against
#' which the observed fit indices are compared, one-sided in the
#' unfavourable direction (CFI from below; RMSEA / SRMR from
#' above).
#' 
#' Items are flagged when the observed value lies outside the
#' chosen percentile of the simulated distribution. At the default
#' 99th-percentile setting, an item is flagged when its observed
#' value is in the worst 1\% of the null distribution.
#' 
#' @param data .
#' @param vars .
#' @param estimator .
#' @param percentile .
#' @param iterations .
#' @param seed .
#' @return A results object containing:
#' \tabular{llllll}{
#'   \code{results$cfaTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$cfaNote} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$cfaPlot} \tab \tab \tab \tab \tab an image \cr
#' }
#'
#' Tables can be converted to data frames with \code{asDF} or \code{\link{as.data.frame}}. For example:
#'
#' \code{results$cfaTable$asDF}
#'
#' \code{as.data.frame(results$cfaTable)}
#'
#' @export
cfacutoff <- function(
    data,
    vars,
    estimator = "WLSMV",
    percentile = 99,
    iterations = 250,
    seed = 42) {

    if ( ! requireNamespace("jmvcore", quietly=TRUE))
        stop("cfacutoff requires jmvcore to be installed (restart may be required)")

    if ( ! missing(vars)) vars <- jmvcore::resolveQuo(jmvcore::enquo(vars))
    if (missing(data))
        data <- jmvcore::marshalData(
            parent.frame(),
            `if`( ! missing(vars), vars, NULL))


    options <- cfacutoffOptions$new(
        vars = vars,
        estimator = estimator,
        percentile = percentile,
        iterations = iterations,
        seed = seed)

    analysis <- cfacutoffClass$new(
        options = options,
        data = data)

    analysis$run()

    analysis$results
}

